"CREATE TABLE IF NOT EXISTS supplier_transactions (\n  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,\n  supplier_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,\n  type TEXT NOT NULL CHECK (type IN ('compra', 'pago')),\n  amount NUMERIC NOT NULL,\n  description TEXT,\n  date TIMESTAMP WITH TIME ZONE DEFAULT NOW(),\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\nCREATE TABLE IF NOT EXISTS purchase_items (\n  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,\n  supplier_transaction_id UUID NOT NULL REFERENCES supplier_transactions(id) ON DELETE CASCADE,\n  product_id UUID NOT NULL REFERENCES products(id) ON DELETE CASCADE,\n  quantity INTEGER NOT NULL,\n  unit_price NUMERIC NOT NULL,\n  total_price NUMERIC NOT NULL,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Enable Row Level Security on both tables\nALTER TABLE supplier_transactions ENABLE ROW LEVEL SECURITY;\nALTER TABLE purchase_items ENABLE ROW LEVEL SECURITY;\n\n-- Policies for supplier_transactions\nCREATE POLICY \"Users can view own transactions\" ON supplier_transactions\n  FOR SELECT TO authenticated USING (true);\n\nCREATE POLICY \"Users can insert own transactions\" ON supplier_transactions\n  FOR INSERT TO authenticated WITH CHECK (true);\n\nCREATE POLICY \"Users can update own transactions\" ON supplier_transactions\n  FOR UPDATE TO authenticated USING (true);\n\nCREATE POLICY \"Users can delete own transactions\" ON supplier_transactions\n  FOR DELETE TO authenticated USING (true);\n\n-- Policies for purchase_items\nCREATE POLICY \"Users can view own purchase items\" ON purchase_items\n  FOR SELECT TO authenticated USING (true);\n\nCREATE POLICY \"Users can insert own purchase items\" ON purchase_items\n  FOR INSERT TO authenticated WITH CHECK (true);\n\nCREATE POLICY \"Users can update own purchase items\" ON purchase_items\n  FOR UPDATE TO authenticated USING (true);\n\nCREATE POLICY \"Users can delete own purchase items\" ON purchase_items\n  FOR DELETE TO authenticated USING (true);\n"